19	  var config: SquirrelConfig?
20	  var panel: SquirrelPanel?
21	  var enableNotifications = false
22	  var showStatusIcon: Bool = true
23	  var statusItem: NSStatusItem?
24	  let updateController = SPUStandardUpdaterController(startingUpdater: true, updaterDelegate: nil, userDriverDelegate: nil)
