139	  func setupRime() {
140	    createDirIfNotExist(path: SquirrelApp.userDir)
141	    createDirIfNotExist(path: SquirrelApp.logDir)
142	    // Expose the log directory to librime plugins.
143	    setenv("RIME_LOG_DIR", SquirrelApp.logDir.path(), 1)
144	    // swiftlint:disable identifier_name
145	    let notification_handler: @convention(c) (UnsafeMutableRawPointer?, RimeSessionId, UnsafePointer<CChar>?, UnsafePointer<CChar>?) -> Void = notificationHandler
146	    let context_object = Unmanaged.passUnretained(self).toOpaque()
147	    // swiftlint:enable identifier_name
148	    rimeAPI.set_notification_handler(notification_handler, context_object)
149	
150	    var squirrelTraits = RimeTraits.rimeStructInit()
151	    squirrelTraits.setCString(Bundle.main.sharedSupportPath!, to: \.shared_data_dir)
152	    squirrelTraits.setCString(SquirrelApp.userDir.path(), to: \.user_data_dir)
153	    squirrelTraits.setCString(SquirrelApp.logDir.path(), to: \.log_dir)
154	    squirrelTraits.setCString("Squirrel", to: \.distribution_code_name)
155	    squirrelTraits.setCString("鼠鬚管", to: \.distribution_name)
156	    squirrelTraits.setCString(Bundle.main.object(forInfoDictionaryKey: kCFBundleVersionKey as String) as! String, to: \.distribution_version)
157	    squirrelTraits.setCString("rime.squirrel", to: \.app_name)
158	    rimeAPI.setup(&squirrelTraits)
159	  }
160	
161	  func startRime(fullCheck: Bool) {
162	    print("Initializing la rime...")
163	    rimeAPI.initialize(nil)
164	    if rimeAPI.start_maintenance(fullCheck) {
165	      _ = rimeAPI.deploy_config_file("squirrel.yaml", "config_version")
166	    }
167	  }
168	
169	  func loadSettings() {
170	    config = SquirrelConfig()
171	    if !config!.openBaseConfig() {
172	      return
173	    }
174	
175	    enableNotifications = config!.getString("show_notifications_when") != "never"
176	    showStatusIcon = config!.getBool("status_icon/show") ?? true
177	    refreshStatusItem()
178	    if let panel = panel, let config = self.config {
179	      panel.load(config: config, forDarkMode: false)
180	      panel.load(config: config, forDarkMode: true)
181	    }
182	  }
183	
184	  func loadSettings(for schemaID: String) {
185	    if schemaID.count == 0 || schemaID.first == "." {
186	      return
187	    }
188	    let schema = SquirrelConfig()
189	    if let panel = panel, let config = self.config {
190	      if schema.open(schemaID: schemaID, baseConfig: config) && schema.has(section: "style") {
191	        panel.load(config: schema, forDarkMode: false)
192	        panel.load(config: schema, forDarkMode: true)
193	      } else {
194	        panel.load(config: config, forDarkMode: false)
195	        panel.load(config: config, forDarkMode: true)
196	      }
197	    }
198	    schema.close()
199	  }
200	
201	  // Detect repeated launches that may indicate a bad configuration loop.
202	  func problematicLaunchDetected() -> Bool {
203	    var detected = false
204	    let logFile = FileManager.default.temporaryDirectory.appendingPathComponent("squirrel_launch.json", conformingTo: .json)
205	    do {
206	      let archive = try Data(contentsOf: logFile, options: [.uncached])
207	      let decoder = JSONDecoder()
208	      decoder.dateDecodingStrategy = .millisecondsSince1970
209	      let previousLaunch = try decoder.decode(Date.self, from: archive)
210	      if previousLaunch.timeIntervalSinceNow >= -2 {
211	        detected = true
212	      }
213	    } catch let error as NSError where error.domain == NSCocoaErrorDomain && error.code == NSFileReadNoSuchFileError {
214	
215	    } catch {
216	      print("Error occurred during processing launch time archive: \(error.localizedDescription)")
217	      return detected
218	    }
219	    do {
220	      let encoder = JSONEncoder()
221	      encoder.dateEncodingStrategy = .millisecondsSince1970
222	      let record = try encoder.encode(Date.now)
223	      try record.write(to: logFile)
224	    } catch {
225	      print("Error occurred during saving launch time to archive: \(error.localizedDescription)")
226	    }
227	    return detected
228	  }
229	
230	  func addObservers() {
231	    let center = NSWorkspace.shared.notificationCenter
232	    center.addObserver(forName: NSWorkspace.willPowerOffNotification, object: nil, queue: nil, using: workspaceWillPowerOff)
233	
234	    let notifCenter = DistributedNotificationCenter.default()
235	    notifCenter.addObserver(forName: .init("SquirrelReloadNotification"), object: nil, queue: nil, using: rimeNeedsReload)
236	    notifCenter.addObserver(forName: .init("SquirrelSyncNotification"), object: nil, queue: nil, using: rimeNeedsSync)
237	    notifCenter.addObserver(forName: .init("SquirrelToggleASCIIModeNotification"), object: nil, queue: nil, using: rimeToggleASCIIMode)
238	    notifCenter.addObserver(forName: .init("SquirrelGetASCIIModeNotification"), object: nil, queue: nil, using: rimeGetASCIIMode)
239	    notifCenter.addObserver(forName: .init(kTISNotifySelectedKeyboardInputSourceChanged as String), object: nil, queue: .main) { [weak self] _ in
240	      self?.updateStatusItemVisibility()
241	      self?.finalizeStrandedComposition()
242	    }
243	  }
