253	extension RimeStringSlice {
254	  /// Bridge the slice's pointer + length to a Swift String, honoring `.length`.
255	  /// librime clips `.length` to the first Unicode character for abbreviated labels
256	  /// when no explicit `abbrev:` field is defined, so reading past `.length` (e.g. with
257	  /// `String(cString:)`) would incorrectly return the full `states:` value.
258	  var asString: String? {
259	    guard let ptr = str else { return nil }
260	    let data = Data(bytes: UnsafeRawPointer(ptr), count: Int(length))
261	    return String(data: data, encoding: .utf8)
262	  }
263	}
