265	// swiftlint:disable:next cyclomatic_complexity
266	private func notificationHandler(contextObject: UnsafeMutableRawPointer?, sessionId: RimeSessionId, messageTypeC: UnsafePointer<CChar>?, messageValueC: UnsafePointer<CChar>?) {
267	  let delegate: SquirrelApplicationDelegate = Unmanaged<SquirrelApplicationDelegate>.fromOpaque(contextObject!).takeUnretainedValue()
268	
269	  let messageType = messageTypeC.map { String(cString: $0) }
270	  let messageValue = messageValueC.map { String(cString: $0) }
271	
272	  if messageType == "deploy" {
273	    switch messageValue {
274	    case "start":
275	      SquirrelApplicationDelegate.showMessage(msgText: NSLocalizedString("deploy_start", comment: ""))
276	    case "success":
277	      SquirrelApplicationDelegate.showMessage(msgText: NSLocalizedString("deploy_success", comment: ""))
278	    case "failure":
279	      SquirrelApplicationDelegate.showMessage(msgText: NSLocalizedString("deploy_failure", comment: ""))
280	    default:
281	      break
282	    }
283	    return
284	  } else if messageType == "option" {
285	    let state = messageValue?.first != "!"
286	    let optionName: String?
287	    if state {
288	      optionName = messageValue
289	    } else if let value = messageValue {
290	      optionName = String(value[value.index(after: value.startIndex)...])
291	    } else {
292	      optionName = nil
293	    }
294	    if let optionName = optionName {
295	      optionName.withCString { name in
296	        func shortLabel() -> String? {
297	          let stateLabelShort = delegate.rimeAPI.get_state_label_abbreviated(sessionId, name, state, true)
298	          return stateLabelShort.asString
299	        }
300	        func longLabel() -> String? {
301	          let stateLabelLong = delegate.rimeAPI.get_state_label_abbreviated(sessionId, name, state, false)
302	          return stateLabelLong.asString
303	        }
304	        if optionName == "ascii_mode" {
305	          delegate.updateStatusIcon(asciiMode: state, schemaLabel: shortLabel())
306	        }
307	        if delegate.enableNotifications {
308	          delegate.showStatusMessage(msgTextLong: longLabel(), msgTextShort: shortLabel())
309	        }
310	      }
311	    }
312	    return
313	  } else if messageType == "property", let messageValue = messageValue,
314	            let eqIndex = messageValue.firstIndex(of: "="), messageValue.first == "_" {
315	    let key = String(messageValue[..<eqIndex])
316	    let value = String(messageValue[messageValue.index(after: eqIndex)...])
317	    Task.detached { @MainActor in
318	      do {
319	        try delegate.panel?.inputController?.handleReservedProperty(key: key, value: value, for: sessionId)
320	      } catch {
321	        print("Error processing handleReservedProperty: \(error)")
322	      }
323	    }
324	    return
325	  }
326	
327	  if delegate.enableNotifications {
328	    if messageType == "schema", let messageValue = messageValue, let schemaName = try? /^[^\/]*\/(.*)$/.firstMatch(in: messageValue)?.output.1 {
329	      delegate.showStatusMessage(msgTextLong: String(schemaName), msgTextShort: String(schemaName))
330	      return
331	    }
332	  }
333	}
334	
335	private extension SquirrelApplicationDelegate {
336	  func showStatusMessage(msgTextLong: String?, msgTextShort: String?) {
337	    if !(msgTextLong ?? "").isEmpty || !(msgTextShort ?? "").isEmpty {
338	      panel?.updateStatus(long: msgTextLong ?? "", short: msgTextShort ?? "")
339	    }
340	  }
341	
342	  func refreshStatusItem() {
343	    if showStatusIcon {
344	      if statusItem == nil {
345	        setupStatusItem()
346	      }
347	    } else if let item = statusItem {
348	      NSStatusBar.system.removeStatusItem(item)
349	      statusItem = nil
350	    }
351	  }
352	
353	  func setupStatusItem() {
354	    let item = NSStatusBar.system.statusItem(withLength: NSStatusItem.variableLength)
355	    if let button = item.button {
356	      button.font = NSFont.systemFont(ofSize: NSFont.systemFontSize, weight: .semibold)
357	      button.toolTip = NSLocalizedString("Squirrel", comment: "")
358	    }
359	    statusItem = item
360	    applyStatusIcon(asciiMode: false, schemaLabel: nil)
361	    updateStatusItemVisibility()
362	  }
363	
364	  func updateStatusItemVisibility() {
365	    guard let statusItem = statusItem else { return }
366	    let currentInputSourceID = SquirrelInstaller.currentInputSourceID() ?? ""
367	    statusItem.isVisible = currentInputSourceID.hasPrefix("im.rime.inputmethod.Squirrel")
368	  }
369	
370	  // macOS 26 does not call deactivateServer when the input source is switched
371	  // away by another process via TISSelectInputSource() (e.g. macism, Input
372	  // Source Pro): the pending composition is stranded and the candidate panel
373	  // is left orphaned on screen (#1140). The input-source-changed notification
374	  // is still delivered, so finalize the composition here as a fallback.
375	  // Switching via the menu bar calls deactivateServer first, making this a
376	  // no-op.
377	  func finalizeStrandedComposition() {
378	    let currentInputSourceID = SquirrelInstaller.currentInputSourceID() ?? ""
379	    guard !currentInputSourceID.hasPrefix("im.rime.inputmethod.Squirrel") else { return }
380	    if let inputController = panel?.inputController {
381	      inputController.deactivateServer(inputController.client())
382	    }
383	  }
384	
385	  func applyStatusIcon(asciiMode: Bool, schemaLabel: String?) {
386	    guard let button = statusItem?.button else { return }
387	    if let schemaLabel = schemaLabel, !schemaLabel.isEmpty {
388	      button.title = schemaLabel
389	    } else {
390	      button.title = asciiMode ? "Ａ" : "中"
391	    }
392	  }
393	
394	  func shutdownRime() {
395	    config?.close()
396	    rimeAPI.finalize()
397	  }
398	
399	  func workspaceWillPowerOff(_: Notification) {
400	    print("Finalizing before logging out.")
401	    self.shutdownRime()
402	  }
403	
404	  func rimeNeedsReload(_: Notification) {
405	    print("Reloading rime on demand.")
406	    self.deploy()
407	  }
408	
409	  func rimeNeedsSync(_: Notification) {
410	    print("Sync rime on demand.")
411	    self.syncUserData()
412	  }
413	
414	  func rimeToggleASCIIMode(_ notification: Notification) {
415	    guard let mode = notification.object as? String else { return }
416	    let enableASCII = mode == "ascii"
417	
418	    if enableASCII {
419	      NotificationCenter.default.post(name: .init("SquirrelSetASCIIModeNotification"), object: true)
420	    } else {
421	      NotificationCenter.default.post(name: .init("SquirrelSetASCIIModeNotification"), object: false)
422	    }
423	  }
424	
425	  func rimeGetASCIIMode(_: Notification) {
426	    NotificationCenter.default.post(name: .init("SquirrelReportASCIIModeNotification"), object: nil)
427	  }
428	
429	  func createDirIfNotExist(path: URL) {
430	    let fileManager = FileManager.default
431	    if !fileManager.fileExists(atPath: path.path()) {
432	      do {
433	        try fileManager.createDirectory(at: path, withIntermediateDirectories: true)
434	      } catch {
435	        print("Error creating user data directory: \(path.path())")
436	      }
437	    }
438	  }
439	}
440	
441	extension NSApplication {
442	  var squirrelAppDelegate: SquirrelApplicationDelegate {
443	    self.delegate as! SquirrelApplicationDelegate
444	  }
445	}
