283	  func handleReservedProperty(key rawKey: String, value rawValue: String, for sessionId: RimeSessionId) throws(ReservedPropertyError) {
284	    guard session == sessionId, session != 0, rimeAPI.find_session(session) else { return }
285	    guard let key = ReservedPropertyKey(rawValue: rawKey) else { throw .unknownInput(rawKey) }
286	    let parsed = try ReservedPropertyValue.parse(rawValue)
287	    switch key {
288	    case .commentHighlight:
289	      specialCommentIndices[.commentHighlight] = try parsed.indices()
290	    case .commentWarning:
291	      specialCommentIndices[.commentWarning] = try parsed.indices()
292	    case .refreshUI:
293	      rimeUpdate(clearReservedComments: false)
294	    }
