20	    isOpen = rimeAPI.config_open("squirrel", &config)
21	    return isOpen
22	  }
23	
24	  func open(schemaID: String, baseConfig: SquirrelConfig?) -> Bool {
25	    close()
26	    isOpen = rimeAPI.schema_open(schemaID, &config)
27	    if isOpen {
28	      self.baseConfig = baseConfig
29	    }
30	    return isOpen
31	  }
32	
33	  func close() {
34	    if isOpen {
35	      _ = rimeAPI.config_close(&config)
36	      baseConfig = nil
37	      isOpen = false
38	    }
39	  }
40	
41	  deinit {
42	    close()
43	  }
44	
45	  func has(section: String) -> Bool {
46	    if isOpen {
47	      var iterator: RimeConfigIterator = .init()
48	      if rimeAPI.config_begin_map(&iterator, &config, section) {
49	        rimeAPI.config_end(&iterator)
50	        return true
51	      }
52	    }
53	    return false
54	  }
55	
56	  func getBool(_ option: String) -> Bool? {
57	    if let cachedValue = cachedValue(of: Bool.self, forKey: option) {
58	      return cachedValue
59	    }
60	    var value = false
61	    if isOpen && rimeAPI.config_get_bool(&config, option, &value) {
62	      cache[option] = value
63	      return value
64	    }
65	    return baseConfig?.getBool(option)
66	  }
67	
68	  func getDouble(_ option: String) -> CGFloat? {
69	    if let cachedValue = cachedValue(of: Double.self, forKey: option) {
70	      return cachedValue
71	    }
72	    var value: Double = 0
73	    if isOpen && rimeAPI.config_get_double(&config, option, &value) {
74	      cache[option] = value
75	      return value
76	    }
77	    return baseConfig?.getDouble(option)
78	  }
79	
80	  func getString(_ option: String) -> String? {
81	    if let cachedValue = cachedValue(of: String.self, forKey: option) {
82	      return cachedValue
83	    }
84	    if isOpen, let value = rimeAPI.config_get_cstring(&config, option) {
85	      cache[option] = String(cString: value)
86	      return String(cString: value)
87	    }
88	    return baseConfig?.getString(option)
89	  }
90	
91	  func getColor(_ option: String, inSpace colorSpace: SquirrelTheme.RimeColorSpace) -> NSColor? {
92	    if let cachedValue = cachedValue(of: NSColor.self, forKey: option) {
93	      return cachedValue
94	    }
95	    if let colorStr = getString(option), let color = color(from: colorStr, inSpace: colorSpace) {
96	      cache[option] = color
97	      return color
98	    }
99	    return baseConfig?.getColor(option, inSpace: colorSpace)
100	  }
101	
102	  func getAppOptions(_ appName: String) -> [String: Bool] {
103	    let rootKey = "app_options/\(appName)"
104	    var appOptions = [String: Bool]()
105	    var iterator = RimeConfigIterator()
106	    _ = rimeAPI.config_begin_map(&iterator, &config, rootKey)
107	    while rimeAPI.config_next(&iterator) {
108	      if let key = iterator.key, let path = iterator.path, let value = getBool(String(cString: path)) {
109	        appOptions[String(cString: key)] = value
110	      }
111	    }
112	    rimeAPI.config_end(&iterator)
113	    return appOptions
114	  }
115	}
116	
117	private extension SquirrelConfig {
118	  func cachedValue<T>(of: T.Type, forKey key: String) -> T? {
119	    return cache[key] as? T
120	  }
121	
122	  func color(from colorStr: String, inSpace colorSpace: SquirrelTheme.RimeColorSpace) -> NSColor? {
123	    if let matched = try? /0x([A-Fa-f0-9]{2})([A-Fa-f0-9]{2})([A-Fa-f0-9]{2})([A-Fa-f0-9]{2})/.wholeMatch(in: colorStr) {
124	      let (_, alpha, blue, green, red) = matched.output
125	      return color(alpha: Int(alpha, radix: 16)!, red: Int(red, radix: 16)!, green: Int(green, radix: 16)!, blue: Int(blue, radix: 16)!, colorSpace: colorSpace)
126	    } else if let matched = try? /0x([A-Fa-f0-9]{2})([A-Fa-f0-9]{2})([A-Fa-f0-9]{2})/.wholeMatch(in: colorStr) {
127	      let (_, blue, green, red) = matched.output
128	      return color(alpha: 255, red: Int(red, radix: 16)!, green: Int(green, radix: 16)!, blue: Int(blue, radix: 16)!, colorSpace: colorSpace)
129	    } else {
130	      return nil
131	    }
132	  }
133	
134	  func color(alpha: Int, red: Int, green: Int, blue: Int, colorSpace: SquirrelTheme.RimeColorSpace) -> NSColor {
135	    switch colorSpace {
136	    case .displayP3:
137	      return NSColor(displayP3Red: CGFloat(red) / 255,
138	                     green: CGFloat(green) / 255,
139	                     blue: CGFloat(blue) / 255,
140	                     alpha: CGFloat(alpha) / 255)
141	    case .sRGB:
142	      return NSColor(srgbRed: CGFloat(red) / 255,
143	                     green: CGFloat(green) / 255,
144	                     blue: CGFloat(blue) / 255,
145	                     alpha: CGFloat(alpha) / 255)
146	    }
147	  }
148	}
