402	      // Expand line length before fullscreen scaling to avoid wasting screen space on narrow text.
403	      let area = contentRect.width * contentRect.height
404	      let screenRatio = maxAllowedWidth / maxAllowedHeight
405	
406	      let optimalTextWidth: CGFloat
407	      if vertical {
